mkdir -p /tmp/sv-c189424ebfb541e0bb580b390ce233d9/typed-meta && cd /tmp/sv-c189424ebfb541e0bb580b390ce233d9/typed-meta && dotnet new console --framework net11.0 -o . --force -n TypedMeta > /dev/null 2>&1 && cat > Program.cs << 'EOF'
using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");

// 2) Probe without throwing — TryGetTypeInfo returns bool + non-generic JsonTypeInfo
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"TryGetTypeInfo succeeded for Person (Type={info!.Type.Name})");
}

// Now probe for a type whose resolver intentionally excludes it:
var limited = new JsonSerializerOptions
{
    // Empty composite resolver → knows about nothing
    TypeInfoResolver = JsonTypeInfoResolver.Combine()
};

if (!limited.TryGetTypeInfo(typeof(Person), out _))
{
    Console.WriteLine("TryGetTypeInfo correctly returned false for Person on limited resolver");
}

Console.WriteLine("Done.");

public record Person(string Name, int Age);
EOF
dotnet run

